import React, { useState, useEffect, useRef } from "react";
import { createRoot } from "react-dom/client";
import { GoogleGenAI } from "@google/genai";
import {
  Sparkles,
  ShieldAlert,
  Video,
  Menu,
  X,
  Loader2,
  BookOpen,
  Upload,
  CheckCircle2,
  Heart,
  Lightbulb,
  Mail,
  Phone,
  Instagram,
  Share2,
  User,
  PlayCircle,
  Filter,
  Search
} from "lucide-react";

// --- Constants & System Prompts ---

const SYSTEM_INSTRUCTION = `You are the official AI assistant for UpwardEase, a nonprofit platform. Your role is strictly backend support: assisting the team in managing content safety.
If content is unsafe, output: "This content includes potentially sensitive emotional expressions. Recommend admin review before publishing."`;

const TOPIC_SYSTEM_PROMPT = `You are the UpwardEase Featured Topic Assistant. Your job is to generate a weekly study or mental health topic for students (e.g., Exam Stress, Time Management, Motivation) and a fun, lighthearted multiple-choice poll related to it.
Return the result in JSON format:
{
  "topicTitle": "Short, catchy title",
  "topicDescription": "2-3 sentences explaining why this matters.",
  "pollQuestion": "A fun question related to the topic",
  "pollOptions": ["Option A", "Option B", "Option C"]
}
Keep it non-political, safe, and encouraging.`;

// --- Components ---

const App = () => {
  const [activeTab, setActiveTab] = useState<"home" | "upload" | "gallery" | "contact" | "admin">("home");
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Always use standard API key init
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const renderContent = () => {
    switch (activeTab) {
      case "home": return <HomeView ai={ai} navigate={setActiveTab} />;
      case "upload": return <UploadView />;
      case "gallery": return <GalleryView />;
      case "contact": return <ContactView />;
      case "admin": return <AdminView ai={ai} />;
      default: return <HomeView ai={ai} navigate={setActiveTab} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 font-sans text-slate-800 overflow-hidden">
      {/* Sidebar Navigation */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-teal-900 text-white transform transition-transform duration-300 ease-in-out ${sidebarOpen ? "translate-x-0" : "-translate-x-full"} md:relative md:translate-x-0 flex flex-col shadow-2xl`}>
        <div className="p-8 flex justify-between items-center border-b border-teal-800">
          <div className="flex items-center gap-3">
            <div className="bg-yellow-400 p-2 rounded-lg">
              <Sparkles className="w-5 h-5 text-teal-900" />
            </div>
            <div>
              <h1 className="text-xl font-extrabold tracking-tight">UpwardEase</h1>
              <p className="text-xs text-teal-200 opacity-80">Student Community</p>
            </div>
          </div>
          <button onClick={() => setSidebarOpen(false)} className="md:hidden text-teal-200 hover:text-white">
            <X className="w-6 h-6" />
          </button>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto">
          <p className="px-4 text-xs font-bold text-teal-400 uppercase tracking-wider mb-2">Platform</p>
          <NavButton active={activeTab === "home"} onClick={() => { setActiveTab("home"); setSidebarOpen(false); }} icon={<Sparkles size={20} />} label="Home & Topics" />
          <NavButton active={activeTab === "upload"} onClick={() => { setActiveTab("upload"); setSidebarOpen(false); }} icon={<Upload size={20} />} label="Upload Video" />
          <NavButton active={activeTab === "gallery"} onClick={() => { setActiveTab("gallery"); setSidebarOpen(false); }} icon={<BookOpen size={20} />} label="Browse Gallery" />
          <NavButton active={activeTab === "contact"} onClick={() => { setActiveTab("contact"); setSidebarOpen(false); }} icon={<Mail size={20} />} label="Contact Us" />

          <p className="px-4 text-xs font-bold text-teal-400 uppercase tracking-wider mb-2 mt-8">Staff</p>
          <NavButton active={activeTab === "admin"} onClick={() => { setActiveTab("admin"); setSidebarOpen(false); }} icon={<ShieldAlert size={20} />} label="Admin Console" />
        </nav>

        <div className="p-6 border-t border-teal-800">
           <div className="flex items-center gap-3 p-3 bg-teal-800 rounded-xl">
             <div className="w-8 h-8 rounded-full bg-teal-600 flex items-center justify-center">
               <span className="font-bold text-sm">U</span>
             </div>
             <div>
               <p className="text-sm font-medium">Student User</p>
               <p className="text-xs text-teal-300">Logged In</p>
             </div>
           </div>
        </div>
      </aside>

      {/* Main Content Wrapper */}
      <div className="flex-1 flex flex-col h-full w-full overflow-hidden relative">
        {/* Mobile Header */}
        <header className="bg-white shadow-sm p-4 flex items-center justify-between md:hidden z-10 relative">
          <button onClick={() => setSidebarOpen(true)} className="text-teal-900">
            <Menu className="w-6 h-6" />
          </button>
          <span className="font-bold text-lg text-teal-900 flex items-center gap-2">
            <Sparkles className="w-4 h-4 text-yellow-500"/> UpwardEase
          </span>
          <div className="w-6" />
        </header>

        {/* Scrollable Main Area */}
        <main className="flex-1 overflow-y-auto scroll-smooth">
          <div className="min-h-full flex flex-col">
            <div className="flex-1 p-4 md:p-8 max-w-7xl mx-auto w-full">
              {renderContent()}
            </div>
            <Footer />
          </div>
        </main>
      </div>
    </div>
  );
};

const NavButton = ({ active, onClick, icon, label }: any) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-xl transition-all duration-200 group ${active ? "bg-teal-700 text-white shadow-md font-semibold" : "text-teal-100 hover:bg-teal-800 hover:pl-5"}`}
  >
    <span className={`${active ? "text-yellow-400" : "text-teal-300 group-hover:text-white"}`}>{icon}</span>
    <span>{label}</span>
  </button>
);

const Footer = () => (
  <footer className="bg-white border-t border-slate-200 py-12 mt-auto">
    <div className="max-w-4xl mx-auto px-6 text-center">
      <div className="flex items-center justify-center gap-2 mb-4">
        <div className="bg-teal-900 p-1.5 rounded-md">
           <Sparkles className="w-4 h-4 text-yellow-400" />
        </div>
        <span className="font-bold text-teal-900 text-lg">UpwardEase</span>
      </div>
      <p className="text-slate-500 mb-6 max-w-lg mx-auto">
        A nonprofit platform for students to share study tips, learning advice, and coping experiences. 
        Together, we make the academic journey a little lighter.
      </p>
      <div className="flex justify-center gap-6 text-sm font-medium text-teal-700 mb-8">
        <button className="hover:underline">Privacy Policy</button>
        <button className="hover:underline">Terms of Service</button>
        <button className="hover:underline">Community Guidelines</button>
        <button className="hover:underline">Contact Us</button>
      </div>
      <p className="text-xs text-slate-400">© UpwardEase {new Date().getFullYear()}. All rights reserved.</p>
    </div>
  </footer>
);

// --- Views ---

const HomeView = ({ ai, navigate }: { ai: GoogleGenAI, navigate: (tab: any) => void }) => {
  const [topicData, setTopicData] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [pollSelection, setPollSelection] = useState<number | null>(null);

  useEffect(() => {
    const fetchTopic = async () => {
      setLoading(true);
      try {
        const response = await ai.models.generateContent({
          model: "gemini-2.5-flash",
          contents: "Generate this week's featured topic and poll.",
          config: { 
            systemInstruction: TOPIC_SYSTEM_PROMPT,
            responseMimeType: "application/json"
          }
        });
        const json = JSON.parse(response.text);
        setTopicData(json);
      } catch (e) {
        console.error(e);
        // Fallback
        setTopicData({
          topicTitle: "Balancing Study & Sleep",
          topicDescription: "This week we're exploring how to get enough rest while keeping up with coursework. Share your routine!",
          pollQuestion: "What is your biggest sleep disruptor?",
          pollOptions: ["Late night scrolling", "Exam anxiety", "Caffeine", "Just not tired"]
        });
      } finally {
        setLoading(false);
      }
    };
    fetchTopic();
  }, []);

  return (
    <div className="space-y-16">

      {/* HERO SECTION */}
      <div className="bg-teal-900 text-white rounded-3xl p-8 md:p-12 relative overflow-hidden shadow-xl">
         {/* Decorative Background Elements */}
         <div className="absolute top-0 right-0 w-80 h-80 bg-teal-800 rounded-full translate-x-1/3 -translate-y-1/3 opacity-50 blur-3xl" />
         <div className="absolute bottom-0 left-0 w-48 h-48 bg-yellow-400 rounded-full -translate-x-1/3 translate-y-1/3 opacity-20 blur-2xl" />

         <div className="relative z-10 max-w-3xl">
           <div className="inline-flex items-center gap-2 bg-teal-800/50 px-4 py-1.5 rounded-full text-teal-200 text-sm font-bold mb-6 border border-teal-700 backdrop-blur-sm">
             <Heart className="w-4 h-4 text-pink-400 fill-current" /> 
             For Students, By Students
           </div>
           <h1 className="text-4xl md:text-6xl font-extrabold mb-6 leading-tight">
             Share your study tips. <br/>
             <span className="text-transparent bg-clip-text bg-gradient-to-r from-yellow-300 to-yellow-500">Find your balance.</span>
           </h1>
           <p className="text-teal-100 text-lg md:text-xl mb-10 max-w-lg leading-relaxed">
             UpwardEase is a safe, nonprofit space for middle school, high school, and college students to share advice on learning and mental well-being.
           </p>
           <div className="flex flex-wrap gap-4">
             <button onClick={() => navigate("upload")} className="bg-yellow-400 text-teal-950 px-8 py-4 rounded-full font-bold hover:bg-yellow-300 transition-transform hover:scale-105 shadow-lg flex items-center gap-2">
               <Video size={20} /> Upload Your Video
             </button>
             <button onClick={() => navigate("gallery")} className="bg-teal-800 text-white px-8 py-4 rounded-full font-bold hover:bg-teal-700 transition-colors border border-teal-700 flex items-center gap-2">
               <BookOpen size={20} /> Browse Gallery
             </button>
           </div>
         </div>
      </div>

      {/* HOW IT WORKS */}
      <section className="text-center max-w-5xl mx-auto">
        <h2 className="text-3xl font-bold text-teal-900 mb-12">How UpwardEase Works</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
           {[
             { icon: <Video className="w-8 h-8 text-teal-600" />, title: "Record", text: "Film a short video sharing a study tip or how you cope with stress." },
             { icon: <Upload className="w-8 h-8 text-teal-600" />, title: "Upload", text: "Submit your video. Our team reviews it to ensure a safe environment." },
             { icon: <Heart className="w-8 h-8 text-teal-600" />, title: "Support", text: "Your video helps other students feel less alone and more prepared." }
           ].map((item, i) => (
             <div key={i} className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
               <div className="w-16 h-16 bg-teal-50 rounded-2xl flex items-center justify-center mx-auto mb-6 rotate-3 group-hover:rotate-6 transition-transform">
                 {item.icon}
               </div>
               <h3 className="text-xl font-bold text-slate-800 mb-3">{item.title}</h3>
               <p className="text-slate-500 leading-relaxed">{item.text}</p>
             </div>
           ))}
        </div>
      </section>

      {/* WEEKLY FEATURED TOPIC */}
      <section className="bg-gradient-to-br from-indigo-50 to-blue-50 rounded-3xl p-8 md:p-12 border border-blue-100">
        <div className="flex flex-col lg:flex-row gap-12 items-center">
          <div className="flex-1 space-y-6">
            <div className="inline-block bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide">
              Weekly Focus
            </div>
            {loading ? (
              <div className="animate-pulse space-y-4">
                <div className="h-8 bg-blue-200 rounded w-3/4"></div>
                <div className="h-4 bg-blue-200 rounded w-full"></div>
                <div className="h-4 bg-blue-200 rounded w-5/6"></div>
              </div>
            ) : (
              <>
                <h2 className="text-3xl md:text-4xl font-bold text-slate-900">{topicData?.topicTitle}</h2>
                <p className="text-lg text-slate-600 leading-relaxed">{topicData?.topicDescription}</p>
                <div className="bg-white/60 p-4 rounded-xl inline-flex items-start gap-3">
                   <Lightbulb className="w-6 h-6 text-yellow-500 flex-shrink-0 mt-1"/>
                   <div>
                     <h4 className="font-bold text-slate-800 text-sm">Have a tip?</h4>
                     <p className="text-sm text-slate-600">This topic affects us all. <span className="font-bold text-teal-600 cursor-pointer hover:underline" onClick={() => navigate("upload")}>Upload a video</span> to share your experience!</p>
                   </div>
                </div>
              </>
            )}
          </div>

          {/* POLL CARD */}
          <div className="w-full lg:w-1/3 bg-white rounded-2xl shadow-lg p-6 border border-slate-100 relative">
             <div className="absolute -top-4 -right-4 bg-yellow-400 text-teal-900 text-xs font-bold px-3 py-1 rounded-full shadow-sm transform rotate-12">
               Weekly Poll
             </div>
             {loading ? (
               <div className="flex items-center justify-center h-48 text-slate-400">
                 <Loader2 className="animate-spin mr-2"/> Loading poll...
               </div>
             ) : (
               <>
                 <h3 className="font-bold text-lg text-slate-800 mb-4">{topicData?.pollQuestion}</h3>
                 <div className="space-y-3">
                   {topicData?.pollOptions?.map((opt: string, idx: number) => (
                     <button 
                       key={idx}
                       onClick={() => setPollSelection(idx)}
                       className={`w-full text-left p-3 rounded-xl border transition-all relative overflow-hidden ${
                         pollSelection === idx 
                           ? "bg-teal-50 border-teal-500 text-teal-900" 
                           : "bg-white border-slate-200 hover:border-teal-300 hover:bg-slate-50"
                       }`}
                     >
                       <span className="relative z-10 flex items-center justify-between">
                         {opt}
                         {pollSelection === idx && <CheckCircle2 className="w-5 h-5 text-teal-600"/>}
                       </span>
                       {/* Mock percentage bar for effect */}
                       {pollSelection !== null && (
                         <div 
                           className="absolute left-0 top-0 bottom-0 bg-teal-100/50 z-0 transition-all duration-1000" 
                           style={{ width: `${Math.floor(Math.random() * 60) + 10}%` }}
                         />
                       )}
                     </button>
                   ))}
                 </div>
                 {pollSelection !== null && (
                   <p className="text-center text-xs text-slate-400 mt-4">Thanks for voting! Results update weekly.</p>
                 )}
               </>
             )}
          </div>
        </div>
      </section>
    </div>
  );
};

// --- Upload View ---
const UploadView = () => {
  const [dragActive, setDragActive] = useState(false);
  const [file, setFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      setFile(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    // Mock API call
    setTimeout(() => {
      setIsSubmitting(false);
      setSubmitted(true);
    }, 2000);
  };

  if (submitted) {
    return (
      <div className="max-w-2xl mx-auto py-12 text-center">
        <div className="bg-white rounded-3xl p-12 shadow-sm border border-slate-100">
           <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6 text-green-600">
             <CheckCircle2 size={40} />
           </div>
           <h2 className="text-3xl font-bold text-slate-900 mb-4">Submission Received!</h2>
           <p className="text-slate-600 mb-8 max-w-md mx-auto">
             Thank you for sharing your story. Our team is reviewing your video to ensuring it meets our community safety guidelines. It will be live in the gallery soon!
           </p>
           <button 
             onClick={() => { setSubmitted(false); setFile(null); }}
             className="bg-teal-600 text-white px-8 py-3 rounded-full font-bold hover:bg-teal-700 transition-colors"
           >
             Upload Another Video
           </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto">
      <h2 className="text-3xl font-bold text-slate-900 mb-2 flex items-center gap-3">
        <Upload className="text-teal-600 w-8 h-8"/> Share Your Story
      </h2>
      <p className="text-slate-500 mb-8">
        Help other students by sharing your study tips, advice, or encouragement.
      </p>

      <form onSubmit={handleSubmit} className="bg-white rounded-3xl p-8 shadow-sm border border-slate-200 space-y-6">

        {/* Video Upload Zone */}
        <div 
          className={`relative border-2 border-dashed rounded-2xl p-10 flex flex-col items-center justify-center text-center transition-colors cursor-pointer min-h-[200px] ${
            dragActive ? "border-teal-500 bg-teal-50" : "border-slate-300 hover:bg-slate-50"
          } ${file ? "bg-teal-50 border-teal-200" : ""}`}
          onDragEnter={handleDrag}
          onDragLeave={handleDrag}
          onDragOver={handleDrag}
          onDrop={handleDrop}
        >
          <input 
            type="file" 
            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
            accept="video/*"
            onChange={handleChange}
          />
          {file ? (
            <div className="flex flex-col items-center">
               <Video className="w-12 h-12 text-teal-600 mb-4" />
               <p className="font-bold text-slate-800 text-lg">{file.name}</p>
               <p className="text-sm text-slate-500 mt-1">{(file.size / (1024 * 1024)).toFixed(2)} MB</p>
               <button type="button" onClick={(e) => { e.preventDefault(); setFile(null); }} className="mt-4 text-xs text-red-500 hover:underline z-20 relative">Remove file</button>
            </div>
          ) : (
            <>
               <div className="bg-teal-100 p-4 rounded-full mb-4">
                 <Upload className="w-8 h-8 text-teal-700" />
               </div>
               <p className="font-bold text-slate-700 text-lg mb-2">Drag and drop your video here</p>
               <p className="text-slate-400 text-sm">or click to browse files (MP4, MOV)</p>
            </>
          )}
        </div>

        {/* Info Fields */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
           <div className="space-y-2">
             <label className="block text-sm font-bold text-slate-700">Video Title</label>
             <input type="text" required placeholder="e.g., My Secret to Acing Math Tests" className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" />
           </div>
           <div className="space-y-2">
             <label className="block text-sm font-bold text-slate-700">Category</label>
             <select className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all bg-white">
               <option>Study Tips</option>
               <option>Exam Prep</option>
               <option>Mental Health & Coping</option>
               <option>Motivation</option>
               <option>College Advice</option>
             </select>
           </div>
        </div>

        <div className="space-y-2">
          <label className="block text-sm font-bold text-slate-700">Description</label>
          <textarea 
            required
            rows={4}
            placeholder="Tell us a little bit about what you're sharing..."
            className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all resize-none" 
          />
        </div>

        <div className="pt-4">
          <button 
            type="submit" 
            disabled={!file || isSubmitting}
            className="w-full bg-teal-600 text-white py-4 rounded-xl font-bold hover:bg-teal-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-md hover:shadow-lg flex items-center justify-center gap-2"
          >
            {isSubmitting ? <Loader2 className="animate-spin" /> : "Submit Video for Review"}
          </button>
          <p className="text-center text-xs text-slate-400 mt-4">
            By uploading, you agree to our Community Guidelines. All videos are reviewed by staff.
          </p>
        </div>
      </form>
    </div>
  );
};

// --- Gallery View ---
const GalleryView = () => {
  // Mock Data
  const videos = [
    { id: 1, title: "How I organize my notes for Finals", author: "Sarah J.", grade: "11th Grade", views: 120, category: "Study Tips", color: "bg-pink-100" },
    { id: 2, title: "Dealing with pre-exam anxiety", author: "Marcus T.", grade: "College Freshman", views: 85, category: "Mental Health", color: "bg-blue-100" },
    { id: 3, title: "Pomodoro technique explained", author: "Emily R.", grade: "10th Grade", views: 230, category: "Productivity", color: "bg-amber-100" },
    { id: 4, title: "My morning routine before school", author: "Alex K.", grade: "12th Grade", views: 95, category: "Motivation", color: "bg-green-100" },
    { id: 5, title: "Chemistry hacks that saved me", author: "Jordan P.", grade: "College Sophomore", views: 310, category: "Exam Prep", color: "bg-purple-100" },
    { id: 6, title: "It's okay to take a break", author: "Lisa M.", grade: "8th Grade", views: 150, category: "Mental Health", color: "bg-teal-100" },
