           <h2 className="text-3xl font-bold text-slate-900 flex items-center gap-3">
             <BookOpen className="text-teal-600 w-8 h-8"/> Browse Gallery
           </h2>
           <p className="text-slate-500 mt-1">Real advice from real students.</p>
         </div>
         <div className="flex gap-2">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input type="text" placeholder="Search topics..." className="pl-10 pr-4 py-2 rounded-lg border border-slate-200 focus:outline-none focus:border-teal-500 text-sm w-full md:w-64" />
            </div>
            <button className="bg-white p-2 border border-slate-200 rounded-lg hover:bg-slate-50 text-slate-600">
               <Filter size={20} />
            </button>
         </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {videos.map(video => (
          <div key={video.id} className="group bg-white rounded-2xl border border-slate-100 shadow-sm hover:shadow-md transition-all overflow-hidden cursor-pointer">
            {/* Thumbnail Placeholder */}
            <div className={`h-48 w-full ${video.color} relative flex items-center justify-center group-hover:opacity-90 transition-opacity`}>
               <PlayCircle className="w-16 h-16 text-slate-900/20 group-hover:scale-110 transition-transform duration-300" />
               <span className="absolute bottom-3 right-3 bg-black/60 text-white text-xs px-2 py-1 rounded-md font-medium">04:20</span>
            </div>

            <div className="p-5">
