const UploadView = ({ user, navigate }: { user: UserType, navigate: any }) => {
  const [dragActive, setDragActive] = useState(false);
  const [file, setFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  // Enforce Login
  if (!user) {
    return (
      <div className="flex flex-col items-center justify-center h-[60vh] text-center">
        <div className="bg-white dark:bg-slate-800 p-12 rounded-[2rem] shadow-xl border border-slate-100 dark:border-slate-700 max-w-md">
           <div className="w-20 h-20 bg-cream dark:bg-slate-700 rounded-full flex items-center justify-center mx-auto mb-6 text-eggplant dark:text-teal-400">
             <User size={40} />
           </div>
           <h2 className="text-3xl font-serif font-bold text-slate-900 dark:text-white mb-4">Join to Share</h2>
           <p className="text-slate-500 dark:text-slate-400 mb-8 leading-relaxed">
             To ensure our community stays safe and supportive, please log in or create an account before uploading.
           </p>
           <button 
             onClick={() => navigate("login")}
             className="w-full bg-eggplant text-white py-4 rounded-xl font-bold hover:bg-eggplant-dark transition-colors text-lg shadow-md"
           >
             Log In / Sign Up
           </button>
        </div>
      </div>
    );
  }

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      setFile(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    // Mock API call
    setTimeout(() => {
      setIsSubmitting(false);
      setSubmitted(true);
    }, 2000);
  };

  if (submitted) {
    return (
      <div className="max-w-2xl mx-auto py-12 text-center">
        <div className="bg-white dark:bg-slate-800 rounded-3xl p-12 shadow-sm border border-slate-100 dark:border-slate-700">
           <div className="w-20 h-20 bg-green-100 dark:bg-green-900 rounded-full flex items-center justify-center mx-auto mb-6 text-green-600 dark:text-green-400">
             <CheckCircle2 size={40} />
           </div>
           <h2 className="text-3xl font-bold text-slate-900 dark:text-white mb-4">Submission Received!</h2>
           <p className="text-slate-600 dark:text-slate-400 mb-8 max-w-md mx-auto">
             Thank you for sharing your story. Our team is reviewing your video to ensuring it meets our community safety guidelines. It will be live in the gallery soon!
           </p>
           <button 
             onClick={() => { setSubmitted(false); setFile(null); }}
             className="bg-eggplant text-white px-8 py-3 rounded-full font-bold hover:bg-eggplant-dark transition-colors"
           >
             Upload Another Video
           </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto">
      <h2 className="text-4xl font-serif font-bold text-slate-900 dark:text-white mb-3 flex items-center gap-3">
         Share Your Story
      </h2>
      <p className="text-slate-500 dark:text-slate-400 mb-10 text-lg">
        Help other students by sharing your study tips, advice, or encouragement.
      </p>

      <form onSubmit={handleSubmit} className="bg-white dark:bg-slate-800 rounded-3xl p-8 shadow-sm border border-slate-200 dark:border-slate-700 space-y-6">

        {/* Video Upload Zone */}
        <div 
          className={`relative border-2 border-dashed rounded-2xl p-10 flex flex-col items-center justify-center text-center transition-colors cursor-pointer min-h-[200px] ${
            dragActive ? "border-eggplant bg-cream dark:bg-teal-900/30" : "border-slate-300 dark:border-slate-600 hover:bg-cream dark:hover:bg-slate-750"
          } ${file ? "bg-cream dark:bg-teal-900/30 border-eggplant/50" : ""}`}
          onDragEnter={handleDrag}
          onDragLeave={handleDrag}
          onDragOver={handleDrag}
          onDrop={handleDrop}
        >
          <input 
            type="file" 
            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
            accept="video/*"
            onChange={handleChange}
          />
          {file ? (
            <div className="flex flex-col items-center">
               <Video className="w-12 h-12 text-eggplant dark:text-teal-400 mb-4" />
               <p className="font-bold text-slate-800 dark:text-white text-lg">{file.name}</p>
               <p className="text-sm text-slate-500 mt-1">{(file.size / (1024 * 1024)).toFixed(2)} MB</p>
               <button type="button" onClick={(e) => { e.preventDefault(); setFile(null); }} className="mt-4 text-xs text-red-500 hover:underline z-20 relative">Remove file</button>
            </div>
          ) : (
            <>
               <div className="bg-cream dark:bg-slate-700 p-4 rounded-full mb-4">
                 <Upload className="w-8 h-8 text-eggplant dark:text-white" />
               </div>
               <p className="font-bold text-slate-700 dark:text-slate-200 text-lg mb-2">Drag and drop your video here</p>
               <p className="text-slate-400 text-sm">or click to browse files (MP4, MOV)</p>
            </>
          )}
        </div>

        {/* Info Fields */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
           <div className="space-y-2">
             <label className="block text-sm font-bold text-slate-700 dark:text-slate-300">Video Title</label>
             <input type="text" required placeholder="e.g., My Secret to Acing Math Tests" className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-600 bg-white dark:bg-slate-700 focus:ring-2 focus:ring-eggplant focus:border-eggplant outline-none transition-all dark:text-white" />
           </div>
           <div className="space-y-2">
             <label className="block text-sm font-bold text-slate-700 dark:text-slate-300">Category</label>
             <select className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-600 bg-white dark:bg-slate-700 focus:ring-2 focus:ring-eggplant focus:border-eggplant outline-none transition-all dark:text-white">
               <option>Study Tips</option>
               <option>Exam Prep</option>
               <option>Mental Health & Coping</option>
               <option>Motivation</option>
               <option>College Advice</option>
             </select>
           </div>
        </div>

        <div className="space-y-2">
          <label className="block text-sm font-bold text-slate-700 dark:text-slate-300">Description</label>
          <textarea 
            required
            rows={4}
            placeholder="Tell us a little bit about what you're sharing..."
            className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-600 bg-white dark:bg-slate-700 focus:ring-2 focus:ring-eggplant focus:border-eggplant outline-none transition-all resize-none dark:text-white" 
          />
        </div>

        <div className="pt-4">
          <button 
            type="submit" 
            disabled={!file || isSubmitting}
            className="w-full bg-eggplant text-white py-4 rounded-xl font-bold hover:bg-eggplant-dark disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-md hover:shadow-lg flex items-center justify-center gap-2"
          >
            {isSubmitting ? <Loader2 className="animate-spin" /> : "Submit Video for Review"}
          </button>
          <p className="text-center text-xs text-slate-400 mt-4">
            By uploading, you agree to our Community Guidelines. All videos are reviewed by staff.
          </p>
        </div>
      </form>
    </div>
  );
};

