const AdminView = ({ ai, user, navigate }: { ai: GoogleGenAI, user: UserType, navigate: any }) => {
  const [submissionText, setSubmissionText] = useState("");
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  // Enforce Admin Login
  if (!user || user.role !== "admin") {
     return (
       <div className="flex flex-col items-center justify-center h-[60vh] text-center">
         <div className="bg-white dark:bg-slate-800 p-12 rounded-[2rem] shadow-lg border border-slate-200 dark:border-slate-700 max-w-md">
            <div className="w-16 h-16 bg-red-100 dark:bg-red-900 rounded-full flex items-center justify-center mx-auto mb-6 text-red-600 dark:text-red-400">
              <ShieldAlert size={32} />
            </div>
            <h2 className="text-2xl font-bold text-slate-900 dark:text-white mb-3">Access Denied</h2>
            <p className="text-slate-500 dark:text-slate-400 mb-8">
              This area is restricted to UpwardEase staff members only.
            </p>
            <button 
              onClick={() => navigate("login")}
              className="w-full bg-slate-800 dark:bg-slate-700 text-white py-3 rounded-xl font-bold hover:bg-slate-900 dark:hover:bg-slate-600 transition-colors"
            >
              Staff Login
            </button>
         </div>
       </div>
     );
  }

  const analyzeContent = async () => {
    if (!submissionText) return;
    setLoading(true);
    try {
      const response = await ai.models.generateContent({
        model: "gemini-3-pro-preview",
        contents: `Analyze this student submission:\n\n${submissionText}`,
        config: {
          systemInstruction: SYSTEM_INSTRUCTION
        }
      });
      setAnalysis(response.text);
    } catch (e) {
      console.error(e);
      setAnalysis("Error analyzing content.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="flex items-center justify-between mb-8">
        <div>
           <h2 className="text-3xl font-serif font-bold text-slate-900 dark:text-white flex items-center gap-3">
             <ShieldAlert className="text-eggplant dark:text-teal-400 w-8 h-8"/> Admin Console
           </h2>
           <p className="text-slate-500 dark:text-slate-400 mt-1">Review user submissions for safety and tagging.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-4">
          <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700">
            <h3 className="font-bold text-slate-800 dark:text-white mb-4 flex items-center gap-2">
              <Video className="w-5 h-5 text-slate-400"/> Submission Content
            </h3>
            <textarea
              className="w-full h-64 border border-slate-200 dark:border-slate-600 bg-slate-50 dark:bg-slate-700 rounded-xl p-4 focus:ring-2 focus:ring-eggplant focus:outline-none resize-none text-sm leading-relaxed dark:text-white"
              placeholder="Paste student video transcript or description here..."
              value={submissionText}
              onChange={(e) => setSubmissionText(e.target.value)}
            />
            <button
              onClick={analyzeContent}
              disabled={loading || !submissionText}
              className="mt-4 w-full bg-eggplant text-white py-3 rounded-xl hover:bg-eggplant-dark font-bold flex justify-center items-center gap-2 shadow-sm transition-all"
            >
              {loading ? <Loader2 className="animate-spin" /> : <Sparkles size={18} />}
              Run Safety Analysis
            </button>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 h-full min-h-[400px]">
          <h3 className="font-bold text-slate-800 dark:text-white mb-4 border-b dark:border-slate-700 pb-4">AI Assessment Report</h3>
          {analysis ? (
             <div className="prose prose-sm max-w-none prose-headings:text-eggplant dark:prose-headings:text-teal-300 prose-p:text-slate-600 dark:prose-p:text-slate-300 text-slate-600 dark:text-slate-300">
                <div dangerouslySetInnerHTML={{ __html: analysis.replace(/\n/g, '<br/>').replace(/\*\*(.*?)\*\*/g, '<b>$1</b>') }} />
             </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-64 text-slate-300 dark:text-slate-600">
              <ShieldAlert className="w-12 h-12 mb-2 opacity-50"/>
              <p>Waiting for submission...</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

