      {/* Main Content */}
      <main className="flex-1 overflow-y-auto scroll-smooth">
        <div className="flex flex-col min-h-full">
          <div className="flex-1 w-full max-w-7xl mx-auto p-4 md:p-8">
            {renderContent()}
          </div>
          <Footer navigate={setActiveTab} darkMode={darkMode} />
        </div>
      </main>
    </div>
  );
};

